#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#define MAX_N 77
#define MAX_M 777
#define MAX_K 777
#define MAX_C 1000000

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N, M, k, s, t;
    scanf("%d %d %d", &N, &M, &k);
    scanf("%d %d", &s, &t);
    int edges[M][3];
    for (int i = 0; i < M; i++) {
        scanf("%d %d %d", &edges[i][0], &edges[i][1], &edges[i][2]);
    }
    int *cuts = (int*)malloc(1 << (N - 2) * sizeof(int));
    int cut_index = 0;
    for (int mask = 0; mask < (1 << (N - 2)); mask++) {
        int cut_weight = 0;
        for (int i = 0; i < M; i++) {
            int u = edges[i][0];
            int v = edges[i][1];
            int c = edges[i][2];
            if ((u == s || (mask & (1 << (u - 2)))) && (v == t || !(mask & (1 << (v - 2))))) {
                cut_weight += c;
            }
        }
        cuts[cut_index++] = cut_weight;
    }
    qsort(cuts, 1 << (N - 2), sizeof(int), compare);
    printf("%d\n", cuts[k - 1]);
    free(cuts);
    return 0;
}

